#!/usr/bin/env node
const { spawn, spawnSync } = require('child_process')
const fs = require('fs')
const path = require('path')

try {
  const envPath = process.env.ENV_FILE || '../../env.json'
  if (path.isAbsolute(envPath)) {
    process.env = Object.assign({}, process.env, require(envPath))
  } else {
    process.env = Object.assign({}, process.env, require(path.resolve(__dirname, envPath)))
  }
} catch {
  process.env = Object.assign({ PORT: '8080' }, process.env)
}

const {
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT,
  BITCOIN_CLI_BIN,
  LIGHTNING_DIR_4,
  LIGHTNING_DIR_5,
  LIGHTNING_DIR_6,
  LIGHTNINGD_BIN,
  LIGHTNING_CLI_BIN
} = process.env

const LIGHTNING_BIN = LIGHTNINGD_BIN || '/usr/local/bin/lightningd'
const LIGHTNING_CLI = LIGHTNING_CLI_BIN || '/usr/local/bin/lightning-cli'
const BITCOIN_CLI = BITCOIN_CLI_BIN || '/usr/local/bin/bitcoin-cli'

const LIGHTNING_DIRS = [
  LIGHTNING_DIR_4 || '/Users/a1707/lightning4',
  LIGHTNING_DIR_5 || '/Users/a1707/lightning5',
  LIGHTNING_DIR_6 || '/Users/a1707/lightning6'
]
const LIGHTNING_PORTS = [9740, 9741, 9742]

const sleep = (ms) => new Promise(r => setTimeout(r, ms))
const log = console.log

async function waitForRPC(dir, timeout = 15000) {
  log(`Waiting for RPC to be ready at ${dir}...`);
  const start = Date.now()
  let attempts = 0;

  while (Date.now() - start < timeout) {
    const res = spawnSync(LIGHTNING_CLI, [
      `--lightning-dir=${dir}`,
      '--network=regtest',
      'getinfo'
    ]);

    if (res.status === 0) {
      log(`RPC check successful for ${dir}.`);
      return true;
    }

    await sleep(500);
    attempts++;

    if (attempts <= 3) {
      log(`... RPC check attempt ${attempts} for ${dir} failed ...`);
      const errorMsg = res.stderr ? res.stderr.toString().trim() : 'No stderr output';
      if (errorMsg) {
        log(`Error: ${errorMsg}`);
      }
      if (res.error && res.error.code === 'ENOENT') {
        log(`(Could not find executable: ${LIGHTNING_CLI}. Check your LIGHTNING_CLI_BIN in env.json)`);
      }
    }
  }
  log(`RPC check timed out for ${dir}.`);
  return false;
}

module.exports = {
  async start() {
    log('=== Starting Lightning nodes (node4–node6) ===')

    // Ensure directories exist initially
    LIGHTNING_DIRS.forEach(dir => {
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true })
    })

    const startNode = async (index, retryCount = 0) => {
      const dir = LIGHTNING_DIRS[index]
      const port = LIGHTNING_PORTS[index]

      if (retryCount > 1) {
        log(`❌ Failed to start lightning node at ${dir} after retries.`)
        return
      }

      log(`→ Starting lightningd for ${dir} on port ${port}`)

      const args = [
        '--network=regtest',
        `--lightning-dir=${dir}`,
        `--bitcoin-rpcuser=${BITCOIN_RPCUSER}`,
        `--bitcoin-rpcpassword=${BITCOIN_RPCPASSWORD}`,
        '--bitcoin-rpcconnect=127.0.0.1',
        `--bitcoin-rpcport=${BITCOIN_RPCPORT}`,
        `--bitcoin-cli=${BITCOIN_CLI}`,
        `--addr=127.0.0.1:${port}`,
        `--log-file=${dir}/debug.log`,
        '--daemon',
        '--disable-plugin=clnrest',
        '--disable-plugin=wss-proxy'
      ]

      return new Promise((resolve, reject) => {
        const child = spawn(LIGHTNING_BIN, args, {
          detached: true,
          stdio: 'pipe',
          env: process.env
        })

        let fatalErrorFound = false

        child.stderr.on('data', (data) => {
          const msg = data.toString()
          // Check for the specific chain reset error
          if (msg.includes('bitcoind has gone backwards')) {
            console.error(`[FATAL ERROR lightningd ${dir}]: ${msg.trim()}`);
            log(`⚠️ Detected stale Lightning state (Bitcoin chain reset). Wiping data for ${dir} and retrying...`)
            fatalErrorFound = true

            // Kill the process if it's still somehow alive (though it likely exited)
            try { process.kill(-child.pid) } catch (e) { }

            // Wipe data
            try {
              fs.rmSync(dir, { recursive: true, force: true })
              fs.mkdirSync(dir, { recursive: true })
            } catch (err) {
              log(`Error wiping dir ${dir}: ${err.message}`)
            }

            // Retry
            resolve(startNode(index, retryCount + 1))
          } else {
            // Only log other errors if not the fatal one we are handling
            if (!fatalErrorFound) console.error(`[lightningd ${dir} stderr]: ${msg}`);
          }
        });

        // If the process exits quickly with error, we might catch it here too
        child.on('exit', async (code) => {
          if (fatalErrorFound) return // Already handling retry

          if (code !== 0) {
            log(`lightningd process for ${dir} exited with code ${code}`)
            // We can't easily detect the *reason* just from code, but if we haven't seen the fatal error yet,
            // we proceed to check RPC. If RPC fails, the user will see logs.
          }

          // Allow some time for startup
          const rpcReady = await waitForRPC(dir, 15000)
          if (rpcReady) {
            log(`✅ Lightning node ready: ${dir}`)
            resolve(true)
          } else {
            log(`⚠️ Lightning node failed to start RPC: ${dir}`)
            log(`Check the log file for errors: cat ${dir}/debug.log`)
            resolve(false)
          }
        })

        child.unref()
      })
    }

    // Start all nodes in parallel or sequence? 
    // Sequence is safer for logging clarity.
    for (let i = 0; i < LIGHTNING_DIRS.length; i++) {
      await startNode(i)
    }

    log('All Lightning nodes startup process complete.')
  },

  async stop() {
    log('Stopping lightningd (best effort)...')
    try {
      const running = spawnSync('pgrep', ['-x', 'lightningd'])
      if (running.status === 0) {
        // pkill -f lightningd matches the command line logic.
        spawnSync('pkill', ['-f', 'lightningd'])
        log('🛑 lightningd stop requested. Waiting for processes to exit...')

        // Wait for processes to exit (max 20s)
        for (let i = 0; i < 20; i++) {
          const check = spawnSync('pgrep', ['-x', 'lightningd'])
          if (check.status !== 0) {
            log('✅ lightningd stopped.')
            return
          }
          await new Promise(r => setTimeout(r, 1000))
        }
        log('⚠️ lightningd did not stop in time.')
      } else {
        log('No lightningd processes found.')
      }
    } catch (err) {
      log('⚠️ Error stopping lightningd:', err.message)
    }
  },

  async reset() {
    log('🗑️  Resetting Lightning nodes...')
    LIGHTNING_DIRS.forEach(dir => {
      if (fs.existsSync(dir)) {
        log(`Removing ${dir}...`)
        fs.rmSync(dir, { recursive: true, force: true })
      }
    })
    log('✅ Lightning data removed.')
  }
}